import React from 'react'
import useToast from './useToast'
import Toast, { TOAST_TYPE } from './Toast.component'
import useToastStore from './useToastStore'

function Example() {
    const { openToast } = useToast()
    const toasts = useToastStore((s) => s.toasts)
    console.log('toast', toasts)
    function openSuccessToast() {
        openToast({
            priority: 10,
            component: <Toast content={'This is a success toast'} type={TOAST_TYPE.SUCCESS} />
        })
    }
    function openErrorToast() {
        openToast({
            priority: 11,
            component: <Toast content={'This is an error toast'} type={TOAST_TYPE.ERROR} />
        })
    }
    function openWarningToast(priority) {
        openToast({
            priority: priority,
            component: <Toast content={'This is a warning toast'} type={TOAST_TYPE.WARNING} />
        })
    }
    return (
        <>
            <button onClick={openSuccessToast}>Open Success Toast</button>
            <button onClick={openErrorToast}>Open Error Toast</button>
            <button onClick={() => openWarningToast(1)}>Open Warning Toast 1</button>
            <button onClick={() => openWarningToast(12)}>Open Warning Toast 2</button>
        </>
    )
}

export default Example
